import{c as i,Q as a,j as t,m as e}from"./chunks/framework.DVkeSyfh.js";const k=JSON.parse('{"title":"Установка","description":"","frontmatter":{},"headers":[],"relativePath":"ru/install.md","filePath":"ru/install.md","lastUpdated":1780017229000}'),d={name:"ru/install.md"};function h(l,s,o,n,p,r){return a(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="установка" tabindex="-1">Установка <a class="header-anchor" href="#установка" aria-label="Permalink to &quot;Установка&quot;">​</a></h1><p>Эта страница описывает, как установить <code>dj-track-similarity</code> локально, включая необязательные группы зависимостей, проверенный CUDA-стек для Windows и требование к FFmpeg. Прочитайте её перед первым запуском, а затем используйте <a href="./cli.html">Справочник CLI</a>, чтобы просканировать папку и запустить сервер.</p><h2 id="требования" tabindex="-1">Требования <a class="header-anchor" href="#требования" aria-label="Permalink to &quot;Требования&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Требование</th><th>Примечания</th></tr></thead><tbody><tr><td>Python <code>&gt;= 3.10</code></td><td>Backend и CLI рассчитаны на Python 3.10 или новее.</td></tr><tr><td>FFmpeg</td><td>Необходим для запуска сервера и декодирования аудио. Должен быть в <code>PATH</code> или задан через <code>DJ_TRACK_SIMILARITY_FFMPEG</code>.</td></tr><tr><td>CUDA GPU</td><td>Необязателен. Ускоряет MAEST, MERT и CLAP. Без GPU работа идёт на CPU.</td></tr></tbody></table><p>Проект устанавливает команду <code>dj-sim</code> из <code>pyproject.toml</code>. После установки <code>dj-sim doctor</code> сообщает, какие версии Python, PyTorch и среды выполнения CUDA он видит.</p><h2 id="группы-зависимостеи" tabindex="-1">Группы зависимостей <a class="header-anchor" href="#группы-зависимостеи" aria-label="Permalink to &quot;Группы зависимостей&quot;">​</a></h2><p>Основные зависимости (<code>numpy</code>, <code>mutagen</code>, <code>pydantic</code>, <code>typer</code>, <code>fastapi</code>, <code>uvicorn</code>, <code>joblib</code>) устанавливаются вместе с базовым пакетом. Необязательные extras включают семейства анализа и локальную лабораторию:</p><table tabindex="0"><thead><tr><th>Группа</th><th>Устанавливает</th><th>Включает</th></tr></thead><tbody><tr><td><code>sonara</code></td><td>Поддержку Sonara</td><td>Извлечение Sonara playlist features и поиск SONARA.</td></tr><tr><td><code>ml</code></td><td>PyTorch/Torchaudio/Torchvision/TorchCodec, Transformers, Hugging Face Hub, LAION-CLAP, MAEST</td><td>Анализ жанров MAEST, MERT embeddings, аудио/текстовые embeddings CLAP.</td></tr><tr><td><code>rhythm-lab</code></td><td>scikit-learn</td><td>Локальное обучение и бенчмаркинг классификаторов в Rhythm Lab.</td></tr><tr><td><code>dev</code></td><td>pytest, Ruff</td><td>Тесты и линтинг.</td></tr></tbody></table><p>Комбинируйте нужные группы — например, <code>.[sonara,ml,dev]</code> для полного локального стека анализа без обучения Rhythm Lab или <code>.[sonara,ml,rhythm-lab,dev]</code>, когда в той же среде также будут обучаться classifier profiles.</p><h2 id="базовая-установка" tabindex="-1">Базовая установка <a class="header-anchor" href="#базовая-установка" aria-label="Permalink to &quot;Базовая установка&quot;">​</a></h2><p>Для рабочей копии разработчика установите проект в editable-режиме:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;.[dev]&quot;</span></span></code></pre></div><p>Этого достаточно для запуска CLI, сервера, сканирования, поиска и экспорта. Семейства анализа, которым нужны модели машинного обучения, дополнительно требуют групп <code>sonara</code> и <code>ml</code>, описанных ниже.</p><h2 id="ml-стек-cuda-windows" tabindex="-1">ML-стек (CUDA, Windows) <a class="header-anchor" href="#ml-стек-cuda-windows" aria-label="Permalink to &quot;ML-стек (CUDA, Windows)&quot;">​</a></h2><p>Проверенный CUDA-стек для Windows:</p><table tabindex="0"><thead><tr><th>Компонент</th><th>Версия</th></tr></thead><tbody><tr><td>PyTorch</td><td><code>2.11.0</code></td></tr><tr><td>Torchaudio</td><td><code>2.11.0</code></td></tr><tr><td>Torchvision</td><td><code>0.26.0</code></td></tr><tr><td>TorchCodec</td><td><code>0.13.0</code></td></tr><tr><td>NumPy</td><td><code>&gt;=1.26,&lt;2.0</code></td></tr><tr><td>Индекс wheel-пакетов PyTorch</td><td><code>https://download.pytorch.org/whl/cu130</code></td></tr></tbody></table><p>Сначала установите подходящие CUDA-сборки wheel из официального индекса wheel-пакетов PyTorch, затем установите остальные ML-зависимости:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install torch</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.11</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> torchvision</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.26</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> torchaudio</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.11</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">url https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">download.pytorch.org</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">whl</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cu130</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install torchcodec</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.13</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">url https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">download.pytorch.org</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">whl</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cu130</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;.[sonara,ml,dev]&quot;</span></span></code></pre></div><p>Используйте <code>.[sonara,ml,rhythm-lab,dev]</code>, когда в той же среде также будут обучаться classifier profiles Rhythm Lab.</p><blockquote><p>Внимание: держите версии PyTorch, Torchaudio, Torchvision и TorchCodec синхронизированными с указанным выше индексом wheel-пакетов CUDA и держите <code>numpy</code> ниже <code>2.0</code>. Смешивание версий — самая частая причина ошибок импорта или декодирования.</p></blockquote><h2 id="ffmpeg" tabindex="-1">FFmpeg <a class="header-anchor" href="#ffmpeg" aria-label="Permalink to &quot;FFmpeg&quot;">​</a></h2><p><code>ffmpeg</code> необходим для надёжного запуска сервера и общего декодирования аудио. Он находится в <code>PATH</code> или настраивается через:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DJ_TRACK_SIMILARITY_FFMPEG</span></span></code></pre></div><p>В Windows декодирование Torchaudio на базе TorchCodec требует <strong>shared</strong>-сборки FFmpeg с DLL в <code>PATH</code>, а не только статический <code>ffmpeg.exe</code>. Проверенная портативная сборка — GyanD <code>ffmpeg 8.1.1-full_build-shared</code> с такой раскладкой:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>C:\\Utils\\tools\\ffmpeg\\bin\\ffmpeg.exe</span></span>
<span class="line"><span>C:\\Utils\\tools\\ffmpeg\\bin\\avcodec-*.dll</span></span>
<span class="line"><span>C:\\Utils\\tools\\ffmpeg\\bin\\avformat-*.dll</span></span></code></pre></div><blockquote><p>Внимание: одного статического <code>ffmpeg.exe</code> недостаточно для декодирования TorchCodec в Windows. Убедитесь, что папка <code>bin</code> с файлами <code>av*.dll</code> находится в <code>PATH</code>.</p></blockquote><h2 id="установка-только-для-cpu" tabindex="-1">Установка только для CPU <a class="header-anchor" href="#установка-только-для-cpu" aria-label="Permalink to &quot;Установка только для CPU&quot;">​</a></h2><p>GPU не обязателен. Установите те же группы <code>sonara</code> и <code>ml</code>, но можно пропустить индекс wheel-пакетов CUDA и позволить PyTorch установить свою сборку по умолчанию:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;.[sonara,ml,dev]&quot;</span></span></code></pre></div><p>Тогда анализ выполняется на CPU. Используйте <code>--device cpu</code> (или оставьте <code>--device auto</code>, который выбирает CPU, когда GPU не виден) для работы MAEST, MERT и CLAP.</p><h2 id="проверка-установки" tabindex="-1">Проверка установки <a class="header-anchor" href="#проверка-установки" aria-label="Permalink to &quot;Проверка установки&quot;">​</a></h2><p>Проверьте команду и среду выполнения:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dj</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sim </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">help</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dj</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sim doctor</span></span></code></pre></div><p><code>dj-sim doctor</code> выводит обнаруженные версии Python и PyTorch, доступность CUDA и устройство, которое выбрал бы <code>auto</code>. Используйте его всякий раз, когда поведение <code>auto</code>, <code>cpu</code> или <code>cuda</code> неясно, либо после изменения пакетов Python, CUDA-сборок wheel, драйверов или конфигурации FFmpeg/TorchCodec. Полный вывод <code>doctor</code> см. в <a href="./cli.html">Справочнике CLI</a>.</p><h2 id="дальнеишие-шаги" tabindex="-1">Дальнейшие шаги <a class="header-anchor" href="#дальнеишие-шаги" aria-label="Permalink to &quot;Дальнейшие шаги&quot;">​</a></h2><ul><li>Прочитайте <a href="./overview.html">Обзор</a> для понимания типичного рабочего процесса.</li><li>Используйте <a href="./cli.html">Справочник CLI</a>, чтобы просканировать папку и запустить сервер.</li><li>См. <a href="./models.html">Модели анализа</a> о том, что делает каждая модель и какие extras ей нужны, и <a href="./analysis.html">Семейства анализа</a>, чтобы решить, какой проход запускать первым.</li></ul>`,36)])])}const E=i(d,[["render",h]]);export{k as __pageData,E as default};
